import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import { Mic, MicOff, Volume2, VolumeX, Trash2, Command, Activity, Cpu, Wifi, AlertCircle, CheckCircle, RefreshCw } from 'lucide-react';
import './App.css';

const App = () => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [interimTranscript, setInterimTranscript] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [commandHistory, setCommandHistory] = useState([]);
  const [systemStatus, setSystemStatus] = useState({
    listening: false,
    processing: false,
    speaking: false,
    connected: false
  });
  const [confirmationDialog, setConfirmationDialog] = useState(null);
  const [ttsEnabled, setTtsEnabled] = useState(true);
  const [backendConnected, setBackendConnected] = useState(false);
  const [transcriptConfidence, setTranscriptConfidence] = useState(0);
  const [audioLevel, setAudioLevel] = useState(0);
  const [showTranscriptVerification, setShowTranscriptVerification] = useState(false);
  const [commandAlternatives, setCommandAlternatives] = useState([]);
  const [recognitionError, setRecognitionError] = useState(null);
  const MIN_CONFIDENCE_THRESHOLD = 0.7;

  const recognitionRef = useRef(null);
  const abortControllerRef = useRef(null);
  const audioContextRef = useRef(null);
  const analyserRef = useRef(null);
  const microphoneRef = useRef(null);
  const animationFrameRef = useRef(null);
  const apiClient = useRef(axios.create({ baseURL: '/api', timeout: 10000 }));
  const speakTextRef = useRef(null);
  const handleCommandRef = useRef(null);

  const speakText = useCallback((text) => {
    if (!ttsEnabled || !text) return;

    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.rate = 1;
    utterance.pitch = 1;
    utterance.volume = 1;

    utterance.onstart = () => {
      setSystemStatus(prev => ({ ...prev, speaking: true }));
    };

    utterance.onend = () => {
      setSystemStatus(prev => ({ ...prev, speaking: false }));
    };

    window.speechSynthesis.speak(utterance);
  }, [ttsEnabled]);

  const handleCommand = useCallback(async (text) => {
    if (!text.trim()) return;

    setSystemStatus(prev => ({ ...prev, processing: true }));
    recognitionRef.current?.stop();

    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();

    try {
      const response = await apiClient.current.post(
        '/process-command',
        { text: text.trim() },
        { signal: abortControllerRef.current.signal }
      );

      const result = response.data;

      setCommandHistory(prev => [
        {
          id: Date.now(),
          command: text,
          response: result.response,
          intent: result.intent,
          timestamp: new Date().toLocaleTimeString()
        },
        ...prev.slice(0, 19)
      ]);

      setAiResponse(result.response);

      if (result.requires_confirmation && result.intent !== 'clarification_needed') {
        setConfirmationDialog({
          message: result.response,
          intent: result.intent,
          parameters: result.parameters
        });
        speakText(result.response);
      } else {
        speakText(result.response);

        if (result.intent !== 'clarification_needed' && result.intent !== 'general_query') {
          const executeResponse = await apiClient.current.post('/execute', {
            intent: result.intent,
            parameters: result.parameters,
            confirmed: false
          });

          const executeResult = executeResponse.data;

          if (executeResult.needs_confirmation) {
            setConfirmationDialog({
              message: executeResult.message,
              intent: result.intent,
              parameters: result.parameters
            });
            speakText(executeResult.message);
          } else if (executeResult.message) {
            setAiResponse(executeResult.message);
            speakText(executeResult.message);
          }
        }
      }
    } catch (error) {
      if (error.name === 'AbortError' || error.code === 'ERR_CANCELED') {
        return;
      }
      console.error('Error processing command:', error);
      const errorMsg = 'Sorry, I encountered an error. Please try again.';
      setAiResponse(errorMsg);
      speakText(errorMsg);
    } finally {
      setSystemStatus(prev => ({ ...prev, processing: false }));
    }
  }, [speakText]);

  useEffect(() => {
    speakTextRef.current = speakText;
    handleCommandRef.current = handleCommand;
  }, [handleCommand, speakText]);

  // Check backend health on mount
  useEffect(() => {
    checkBackendConnection();
    const interval = setInterval(checkBackendConnection, 30000);
    return () => clearInterval(interval);
  }, []);

  const checkBackendConnection = async () => {
    try {
      const response = await apiClient.current.get('/health', { timeout: 5000 });
      setBackendConnected(response.data.status === 'healthy');
    } catch (error) {
      setBackendConnected(false);
    }
  };

  // Initialize speech recognition with enhanced settings
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.maxAlternatives = 3;

      recognitionRef.current.onstart = () => {
        setIsListening(true);
        setSystemStatus(prev => ({ ...prev, listening: true }));
        setRecognitionError(null);
        startAudioVisualization();
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
        setSystemStatus(prev => ({ ...prev, listening: false }));
        stopAudioVisualization();

        // Auto-restart if not manually stopped
        if (!recognitionError) {
          setTimeout(() => {
            try {
              recognitionRef.current?.start();
            } catch (e) {
              console.log('Auto-restart failed:', e);
            }
          }, 500);
        }
      };

      recognitionRef.current.onresult = (event) => {
        let finalTranscript = '';
        let interimTranscript = '';
        let alternatives = [];
        let confidence = 0;

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const result = event.results[i];
          const transcript = result[0].transcript;
          confidence = result[0].confidence || 0.8;

          // Collect alternatives
          if (result.length > 1) {
            alternatives = Array.from(result).slice(1).map(alt => ({
              text: alt.transcript,
              confidence: alt.confidence || 0.5
            }));
          }

          if (result.isFinal) {
            finalTranscript += transcript;
          } else {
            interimTranscript += transcript;
          }
        }

        setTranscriptConfidence(confidence);

        if (finalTranscript) {
          setTranscript(finalTranscript);
          setInterimTranscript('');
          setCommandAlternatives(alternatives);

          // Check confidence threshold
          if (confidence < MIN_CONFIDENCE_THRESHOLD) {
            setShowTranscriptVerification(true);
            speakTextRef.current?.("I didn't catch that clearly. Please confirm or correct what you said.");
          } else {
            handleCommandRef.current?.(finalTranscript);
          }
        } else {
          setInterimTranscript(interimTranscript);
        }
      };

      recognitionRef.current.onerror = (event) => {
        console.error('Speech recognition error:', event.error);
        setRecognitionError(event.error);
        setIsListening(false);
        setSystemStatus(prev => ({ ...prev, listening: false }));

        // Handle specific errors
        if (event.error === 'no-speech') {
          setAiResponse('No speech detected. Please try speaking louder or closer to the microphone.');
        } else if (event.error === 'audio-capture') {
          setAiResponse('Microphone not available. Please check your audio settings.');
        } else if (event.error === 'not-allowed') {
          setAiResponse('Microphone access denied. Please allow microphone permissions.');
        }
      };
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
      stopAudioVisualization();
    };
  }, [recognitionError]);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert('Speech recognition is not supported in your browser. Please use Chrome.');
      return;
    }

    if (isListening) {
      recognitionRef.current.stop();
      stopAudioVisualization();
    } else {
      setTranscript('');
      setInterimTranscript('');
      setTranscriptConfidence(0);
      setCommandAlternatives([]);
      setShowTranscriptVerification(false);
      setRecognitionError(null);
      recognitionRef.current.start();
    }
  };

  // Audio visualization
  const startAudioVisualization = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      microphoneRef.current = stream;
      audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 256;

      const source = audioContextRef.current.createMediaStreamSource(stream);
      source.connect(analyserRef.current);

      const updateAudioLevel = () => {
        if (!analyserRef.current) return;
        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
        analyserRef.current.getByteFrequencyData(dataArray);
        const average = dataArray.reduce((a, b) => a + b) / dataArray.length;
        setAudioLevel(average);
        animationFrameRef.current = requestAnimationFrame(updateAudioLevel);
      };

      updateAudioLevel();
    } catch (err) {
      console.log('Audio visualization not available:', err);
    }
  };

  const stopAudioVisualization = () => {
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
    }
    if (microphoneRef.current) {
      microphoneRef.current.getTracks().forEach(track => track.stop());
    }
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    setAudioLevel(0);
  };

  const handleTranscriptCorrection = (correctedText) => {
    setTranscript(correctedText);
    setShowTranscriptVerification(false);
    handleCommand(correctedText);
  };

  const retryListening = () => {
    setShowTranscriptVerification(false);
    setTranscript('');
    setTranscriptConfidence(0);
    recognitionRef.current?.start();
  };

  const executeCommand = async (intent, parameters, confirmed = false) => {
    try {
      const response = await apiClient.current.post('/execute', {
        intent,
        parameters,
        confirmed
      });

      const result = response.data;

      if (result.needs_confirmation && !confirmed) {
        setConfirmationDialog({
          message: result.message,
          intent,
          parameters
        });
        speakText(result.message);
      } else {
        const successMsg = result.message || 'Action completed successfully.';
        setAiResponse(successMsg);
        speakText(successMsg);
      }
    } catch (error) {
      console.error('Error executing command:', error);
      const errorMsg = 'Failed to execute the command.';
      setAiResponse(errorMsg);
      speakText(errorMsg);
    }
  };

  const handleConfirmation = async (confirmed) => {
    if (confirmationDialog) {
      if (confirmed) {
        await executeCommand(confirmationDialog.intent, confirmationDialog.parameters, true);
      } else {
        const cancelMsg = 'Action cancelled.';
        setAiResponse(cancelMsg);
        speakText(cancelMsg);
      }
      setConfirmationDialog(null);
    }
  };

  const clearHistory = () => {
    setCommandHistory([]);
    setTranscript('');
    setInterimTranscript('');
    setAiResponse('');
    setTranscriptConfidence(0);
    setShowTranscriptVerification(false);
  };

  const stopSpeaking = () => {
    window.speechSynthesis.cancel();
    setSystemStatus(prev => ({ ...prev, speaking: false }));
  };

  return (
    <div className="app">
      <header className="app-header">
        <div className="logo">
          <Command size={32} />
          <h1>Voice AI Assistant</h1>
        </div>
        <div className="header-controls">
          <button 
            className="icon-btn"
            onClick={() => setTtsEnabled(!ttsEnabled)}
            title={ttsEnabled ? 'Disable voice responses' : 'Enable voice responses'}
          >
            {ttsEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
          </button>
          <button 
            className="icon-btn"
            onClick={clearHistory}
            title="Clear history"
          >
            <Trash2 size={20} />
          </button>
          <div className={`status-indicator ${backendConnected ? 'connected' : 'disconnected'}`}>
            <Wifi size={16} />
            <span>{backendConnected ? 'Connected' : 'Offline'}</span>
          </div>
        </div>
      </header>

      <main className="app-main">
        <div className="main-interface">
          {/* Voice Input Section */}
          <div className="voice-section">
            <div className={`mic-container ${isListening ? 'listening' : ''}`}>
              <button 
                className={`mic-btn ${isListening ? 'active' : ''}`}
                onClick={toggleListening}
              >
                {isListening ? <Mic size={48} /> : <MicOff size={48} />}
              </button>
              {isListening && <div className="mic-ripple"></div>}
            </div>

            {/* Audio Level Visualization */}
            {isListening && (
              <div className="audio-visualizer">
                <div className="audio-label">Audio Level</div>
                <div className="audio-bar-container">
                  <div 
                    className={`audio-bar ${audioLevel < 20 ? 'low' : audioLevel < 60 ? 'medium' : 'good'}`}
                    style={{ width: `${Math.min(audioLevel * 1.5, 100)}%` }}
                  />
                </div>
                <div className="audio-hint">
                  {audioLevel < 20 ? 'Speak louder or closer to mic' : audioLevel > 100 ? 'Reduce background noise' : 'Good audio level'}
                </div>
              </div>
            )}

            <div className="transcript-display">
              {interimTranscript && (
                <p className="interim-text">{interimTranscript}</p>
              )}
              {transcript && (
                <>
                  <p className="final-text">{transcript}</p>
                  {transcriptConfidence > 0 && (
                    <div className={`confidence-indicator ${transcriptConfidence >= MIN_CONFIDENCE_THRESHOLD ? 'good' : 'low'}`}>
                      {transcriptConfidence >= MIN_CONFIDENCE_THRESHOLD ? <CheckCircle size={14} /> : <AlertCircle size={14} />}
                      <span>Confidence: {Math.round(transcriptConfidence * 100)}%</span>
                    </div>
                  )}
                </>
              )}
              {!transcript && !interimTranscript && (
                <p className="placeholder-text">
                  {isListening ? 'Listening... Speak clearly for best results' : 'Click the microphone to start'}
                </p>
              )}
            </div>

            <div className="system-status">
              <div className={`status-item ${systemStatus.listening ? 'active' : ''}`}>
                <Mic size={16} />
                <span>Listening</span>
              </div>
              <div className={`status-item ${systemStatus.processing ? 'active' : ''}`}>
                <Cpu size={16} />
                <span>Processing</span>
              </div>
              <div className={`status-item ${systemStatus.speaking ? 'active' : ''}`}>
                <Activity size={16} />
                <span>Speaking</span>
              </div>
            </div>
          </div>

          {/* AI Response Section */}
          <div className="response-section">
            <h2>Assistant Response</h2>
            <div className="response-box">
              {aiResponse ? (
                <p>{aiResponse}</p>
              ) : (
                <p className="placeholder">Your assistant response will appear here...</p>
              )}
            </div>
            {systemStatus.speaking && (
              <button className="stop-btn" onClick={stopSpeaking}>
                Stop Speaking
              </button>
            )}
          </div>
        </div>

        {/* Command History */}
        <div className="history-section">
          <h2>Command History</h2>
          <div className="history-list">
            {commandHistory.length === 0 ? (
              <p className="empty-history">No commands yet. Start speaking!</p>
            ) : (
              commandHistory.map((item) => (
                <div key={item.id} className="history-item">
                  <div className="history-header">
                    <span className="intent-badge">{item.intent}</span>
                    <span className="timestamp">{item.timestamp}</span>
                  </div>
                  <p className="command-text">{item.command}</p>
                  <p className="response-text">{item.response}</p>
                </div>
              ))
            )}
          </div>
        </div>
      </main>

      {/* Transcript Verification Dialog */}
      {showTranscriptVerification && (
        <div className="confirmation-overlay">
          <div className="confirmation-dialog verification-dialog">
            <h3>Did you say this correctly?</h3>
            <p className="recognized-text">"{transcript}"</p>
            <p className="confidence-warning">Confidence: {Math.round(transcriptConfidence * 100)}% (below optimal)</p>

            {commandAlternatives.length > 0 && (
              <div className="alternatives-section">
                <p>Or did you mean:</p>
                <div className="alternatives-list">
                  {commandAlternatives.map((alt, index) => (
                    <button 
                      key={index}
                      className="alternative-btn"
                      onClick={() => handleTranscriptCorrection(alt.text)}
                    >
                      "{alt.text}"
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="verification-buttons">
              <button 
                className="confirm-btn confirm"
                onClick={() => handleTranscriptCorrection(transcript)}
              >
                <CheckCircle size={16} /> Yes, proceed
              </button>
              <button 
                className="confirm-btn retry"
                onClick={retryListening}
              >
                <RefreshCw size={16} /> Try again
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Dialog */}
      {confirmationDialog && (
        <div className="confirmation-overlay">
          <div className="confirmation-dialog">
            <h3>Confirmation Required</h3>
            <p>{confirmationDialog.message}</p>
            <div className="confirmation-buttons">
              <button 
                className="confirm-btn confirm"
                onClick={() => handleConfirmation(true)}
              >
                Confirm
              </button>
              <button 
                className="confirm-btn cancel"
                onClick={() => handleConfirmation(false)}
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      <footer className="app-footer">
        <p>Voice-Controlled AI Laptop Assistant • Powered by Gemini AI</p>
      </footer>
    </div>
  );
};

export default App;
